import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class CSVFormatTest {

    private CSVFormat csvFormatDefault;

    @BeforeEach
    public void setUp() {
        csvFormatDefault = CSVFormat.DEFAULT;
    }

    @Test
    public void testWithEscape_char_nonNull() {
        char escapeChar = '\\';
        CSVFormat result = csvFormatDefault.withEscape(escapeChar);
        assertNotNull(result);
        assertEquals(Character.valueOf(escapeChar), result.getEscape());
    }

    @Test
    public void testWithEscape_char_nullEscape() {
        // Use reflection to invoke private withEscape(Character)
        try {
            Method withEscapeCharMethod = CSVFormat.class.getDeclaredMethod("withEscape", Character.class);
            withEscapeCharMethod.setAccessible(true);

            // Passing null should be handled gracefully, but since withEscape(char) cannot pass null,
            // we test withEscape(Character) with null directly through reflection.
            CSVFormat result = (CSVFormat) withEscapeCharMethod.invoke(csvFormatDefault, new Object[] { null });
            assertNotNull(result);
            assertNull(result.getEscape());
        } catch (Exception e) {
            fail("Reflection invocation failed: " + e.getMessage());
        }
    }
}
